#include <string.h> // for strncpy
if (argc[1]) {  // first, check if the argument actually exists
    strncpy(buf, argc[1], sizeof(buf) - 1);  // ensure only 255 chars are copied
    buf[sizeof(buf) - 1] = '\0';  // explicitly terminate
} else {
    buf[0] = '\0';  // handle case where there is no argument
}
